form:Form.form:Scripts:
		

		function ONLOAD_custom()
{   
	//Recupero el numero del Modelo elejido por defecto en el parametro
	var np = new NomadProxy("", ut);
	var nSQL = np.SQLService();    
	var param = nSQL.GetOBJ(Ctrl("main").getResource("QRY_PARAMETRO"), "");	
	//Si existe el parametro el cliente controla la licencia
	if (typeof(param.d_valor) != "undefined")
	{  
		var v_param = param.d_valor.toString();
		Ctrl("modelo").SetXValue(v_param);		        
	} 

}	

			function PREV_exec_qry()
{
	if(Ctrl("empresa").GetXValue()=="")
		return "Es requerido especificar la Empresa.";

	if(Ctrl("liquidacion").GetXValue()=="" && Ctrl("periodo").GetXValue()=="")
		return "Es requerido especificar la Liquidacion o el Período.";

	if(Ctrl("liquidacion").GetXValue()!="" && Ctrl("periodo").GetXValue()!="")
		return "Sólo se permite especificar la Liquidación o el Período.";

	if(Ctrl("liquidacion").GetXValue()!="")
		Ctrl("where").SetXValue("LEG.oi_personal_emp in (select EXT.oi_personal_emp from LIQ25_PERSONAL_LIQ as EXT where EXT.oi_liquidacion=" + Ctrl("liquidacion").GetXValue() + " )");
	else                                                                                                                                                                             
		Ctrl("where").SetXValue("LEG.oi_personal_emp in (select EXT.oi_personal_emp from LIQ25_PERSONAL_LIQ as EXT, LIQ19_LIQUIDACION as LIQ where EXT.oi_liquidacion = LIQ.oi_liquidacion and LIQ.oi_empresa=" + Ctrl("empresa").GetXValue() + " and LIQ.e_periodo=" + Ctrl("periodo").GetXValue() + " )");

  return null;
}

function deshabilitarPer()
{   
	clearFILTER();
	if(Ctrl("liquidacion").GetXValue()!="")
		CtrlEnabled('periodo',false);
	else
	{
		CtrlEnabled('periodo',true);
		Ctrl('orden1').SetXValue('');
		Ctrl('orden2').SetXValue('');
	}
}

function deshabilitarLiq()
{   
	clearFILTER();
	if(Ctrl("periodo").GetXValue()!="")
	{
		CtrlEnabled('liquidacion',false);
		CtrlEnabled('rwerOrden',false);
		Ctrl('orden1').SetXValue('');
		Ctrl('orden2').SetXValue('');
	}		
	else
	{
		CtrlEnabled('liquidacion',true);
		CtrlEnabled('rwerOrden',true);
	}

}

function habilitarTodo()
{ 
	clearFILTER();
	CtrlEnabled('liquidacion',true);
	CtrlEnabled('rwerOrden',true);
	CtrlEnabled('periodo',true); 

}   

function val_orden() 
{
if (Ctrl('orden1').GetXValue() == "ORG03_UBICACIONES.c_ubicacion" || Ctrl('orden1').GetXValue() == "ORG03_UBICACIONES.d_ubicacion")
 {
 	CtrlEnabled('orden2',true);
 }
else
 {
  CtrlEnabled('orden2',false);
  Ctrl("orden2").SetXValue("");
 } 
}
